package com.aadil.jobtracker.UserController;import com.aadil.jobtracker.Validation.UserResponseDTO;import com.aadil.jobtracker.Validation.UserRequestDTO;import com.aadil.jobtracker.UserService.UserServiceImp;import jakarta.validation.Valid;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.List;import java.util.Optional;@RestController@RequestMapping("/users")public class UserController {    private final UserServiceImp userService;    public UserController(UserServiceImp userService) {        this.userService = userService;    }    @PostMapping()    public ResponseEntity<UserResponseDTO> createUser(@Valid@RequestBody UserRequestDTO dto){        return ResponseEntity.status(201).body(userService.createUser(dto));    }    @PostMapping("/bulk")    public ResponseEntity<List<UserResponseDTO>> createUsers(@Valid @RequestBody List<UserRequestDTO>dtos){        return ResponseEntity.status(201).body(userService.createUsers(dtos));    }    @GetMapping("/{id}")    public ResponseEntity<Optional<UserResponseDTO>> getUser(@PathVariable Long id){        return ResponseEntity.ok(userService.getUser(id));    }    @GetMapping("/bulk")    public ResponseEntity<List<UserResponseDTO>> getUsersById(@RequestParam List<Long>ids){        return ResponseEntity.ok(userService.getUsersById(ids));    }    @GetMapping("/all")    public ResponseEntity<List<UserResponseDTO>> getAllUser(){        return ResponseEntity.ok(userService.getAllUsers());    }    @PutMapping("/{id}")    public ResponseEntity<UserResponseDTO> updateUser(@PathVariable Long id, @Valid @RequestBody UserRequestDTO dto){        return userService.updateUser(id, dto).map(ResponseEntity::ok).orElse(ResponseEntity.notFound().build());    }    @DeleteMapping("/{id}")    public ResponseEntity<UserResponseDTO> deleteUser(@PathVariable Long id){        userService.deleteUser(id);        return ResponseEntity.noContent().build();    }    @DeleteMapping("/all")    public ResponseEntity<UserResponseDTO> deleteAll(){        userService.deleteAll();        return ResponseEntity.noContent().build();    }    @DeleteMapping("/batch")    public ResponseEntity<List<UserResponseDTO>>deleteAllById(@PathVariable List<Long>ids){        userService.deleteById(ids);        return ResponseEntity.noContent().build();    }}